import React from 'react'

export const Clothes = ({props}) => {
    console.log(props.photos[0])
  return (
    <div>

    <div>
        <h1>Clothes {props.iname} {props.imrp}</h1>
        <div className="mt-2 grid grid-cols-3 gap-2 md:grid-cols-4 lg:grid-cols-6" > 
        {
          props.photos && (
            <div>
                <img  className="rounded-2xl w-full object-cover h-32" alt="img not found" src={'http://localhost:5000/'+props.photos[0]} />
                </div>
            )
          }
        </div>
    </div>
      </div>
  )
}
